/// <summary>
/// For storing the Transfer order info which retrieved and transform from the IF table.
/// </summary>
class KJP_SM_ArrivalResultsTransferInfoClass
{
    private InventTransferLine          inventTransferLine;
    private InventTransferId            transferId;
    private LineNum                     lineNum;
    private InventTransferQty           qtyTransfer;
    private InventTransferReceiveDate   receiveDate;

}

Method.Source:
/// <summary>
/// Contructor for current class
/// </summary>
/// <returns>Instance of current class</returns>
public static KJP_SM_ArrivalResultsTransferInfoClass construct()
{
    return new KJP_SM_ArrivalResultsTransferInfoClass();
}

    /// <summary>
    /// Get the transfer line info from business table base on InventTransferId and LineNum retrieved from the IF table.
    /// </summary>
    public void getTransferInfo()
    {
        UnitOfMeasureSymbol     salesUnit;
        UnitOfMeasureSymbol     inventUnit;

        inventTransferLine  = InventTransferLine::find(transferId, lineNum);

        salesUnit           = InventTableModule::getUnitIdByModuleType(inventTransferLine.ItemId, ModuleInventPurchSales::Sales);
        inventUnit          = InventTableModule::getUnitIdByModuleType(inventTransferLine.ItemId, ModuleInventPurchSales::Invent);

        qtyTransfer         = EcoResProductUnitConverter::convertGivenUnitSymbolsForReleasedProduct(
                                inventTransferLine.ItemId,
                                inventTransferLine.InventDimId,
                                qtyTransfer,
                                salesUnit,
                                inventUnit);
    }

/// <summary>
/// Parameterized the Transfer Line
/// </summary>
/// <returns>InventTransferLine</returns>
public InventTransferLine parmInventTransferLine()
{
    return inventTransferLine;
}

/// <summary>
/// Parameterized the InventTransIdReceive of Transfer Line
/// </summary>
/// <returns>InventTransIdReceive</returns>
public InventTransIdReceive parmInventTransIdReceive()
{
    return this.parmInventTransferLine().InventTransIdReceive;
}

/// <summary>
/// Parameterized the InventTransIdTransitFrom of Transfer Line
/// </summary>
/// <returns>InventTransIdTransitFrom</returns>
public InventTransIdReceiveTransit parmInventTransIdTransitFrom()
{
    return this.parmInventTransferLine().InventTransIdTransitFrom;
}

    /// <summary>
    /// VoucherNumber - Transfer Id
    /// </summary>
    /// <param name = "_transferId">Transfer Id</param>
    /// <returns>Transfer Id</returns>
    public InventTransferId parmTransferId(InventTransferId _transferId = transferId)
    {
        transferId = _transferId;

        return transferId;
    }

    /// <summary>
    /// LineNo - Line Num
    /// </summary>
    /// <param name = "_lineNum">Line Num</param>
    /// <returns>Line Num</returns>
    public LineNum parmLineNum(LineNum _lineNum = lineNum)
    {
        lineNum = _lineNum;

        return lineNum;
    }

    /// <summary>
    /// ArrivalTotalNumber - Qty Transfer
    /// </summary>
    /// <param name = "_qtyTransfer">Qty Transfer</param>
    /// <returns>Qty Transfer</returns>
    public InventTransferQty parmQtyTransfer(InventTransferQty _qtyTransfer = qtyTransfer)
    {
        qtyTransfer = _qtyTransfer;

        return qtyTransfer;
    }

    /// <summary>
    /// ReceiptDate - Receive Date
    /// </summary>
    /// <param name = "_receiveDate">Receive Date</param>
    /// <returns>Receive Date</returns>
    public InventTransferReceiveDate parmReceiveDate(InventTransferReceiveDate _receiveDate = receiveDate)
    {
        receiveDate = _receiveDate;

        return receiveDate;
    }
